// sets with the same Im-fold asymmetry as the Heart Mandelbrot but with
// fixed parameter. Near c=(−0.60, 0.40) the Julia set is connected,
// showing a flame-shaped central body with asymmetric trailing filaments
// — the Im fold causes the set to "point" in one direction.
// Derivative: 2(Re+i|Im|)·der (Julia mode, no +1 term).
// Supports normal-map shading (colorScheme 50-63).
uniform float uTime;
uniform vec2  uResolution;
uniform vec2  uCenter;
uniform float uZoom;
uniform float uIterations;
uniform float uBailout;
uniform float uColorScheme;
uniform float uTransparentBg;

